#include &lt;stdio.h&gt;
#include &lt;assert.h&gt;

void calculate_speed(int distance, int time) {
    // Trap impossible state. If time is 0, the program will instantly abort
    // printing: "Assertion 'time > 0' failed at main.c:6"
    assert(time > 0);

    int speed = distance / time;
    printf("Speed: %d\n", speed);
}

#include &lt;stdio.h&gt;

// A custom macro that doesn't abort the whole suite on failure, 
// allowing multiple tests to run and reporting the final score.
#define TEST_EQ(expected, actual) do { \
    if ((expected) != (actual)) { \
        printf("[FAIL] %s:%d: Expected %d, got %d\n", __FILE__, __LINE__, (expected), (actual)); \
        failures++; \
    } else { \
        printf("[PASS] %s:%d\n", __FILE__, __LINE__); \
        passes++; \
    } \
} while(0)

int passes = 0;
int failures = 0;

int add(int a, int b) { return a + b; }

int main() {
    TEST_EQ(5, add(2, 3));
    TEST_EQ(10, add(5, 5));
    printf("Results: %d Passed, %d Failed\n", passes, failures);
    return failures == 0 ? 0 : 1;
}

#include &lt;assert.h&gt;
#include &lt;stdint.h&gt;

// _Static_assert (or static_assert in C11) evaluates at COMPILE TIME.
// It incurs zero runtime overhead. If it fails, the binary refuses to compile.
// This is elite-level architecture enforcement.

struct NetworkHeader {
    uint32_t id;
    uint16_t length;
    uint8_t flags;
}; // 7 bytes theoretically, but compiler padding might make it 8.

// We mandate that this struct must be exactly 7 bytes to match a hardware spec.
static_assert(sizeof(struct NetworkHeader) == 7, "Header struct contains illegal padding!");

