// --- production.c ---
#include &lt;stdio.h&gt;
// Pretend this reads from a physical I2C hardware pin
int read_sensor() { return 100; }

int check_alarm() {
    if (read_sensor() > 90) return 1; // ALARM
    return 0;
}

// --- test.c ---
#include &lt;stdio.h&gt;
#include &lt;assert.h&gt;

// We create a global variable to control what our mock returns
int mock_sensor_val = 0;

// The Linker will hijack all calls to read_sensor and route them here
int __wrap_read_sensor() {
    return mock_sensor_val;
}

int main() {
    // Inject fake hardware data
    mock_sensor_val = 95;
    assert(check_alarm() == 1); // Test passes without touching hardware!
    return 0;
}
// Compile: gcc production.c test.c -Wl,--wrap=read_sensor

#include &lt;stdio.h&gt;

// If GCC --wrap is not available, we inject dependencies manually.
// We define a struct containing function pointers (A poor man's Interface).
typedef struct {
    int (*read_sensor)(void);
} HardwareAPI;

// The logic function relies entirely on the injected API.
int check_alarm(HardwareAPI *api) {
    if (api->read_sensor() > 90) return 1;
    return 0;
}

// --- In our Test File ---
int fake_read() { return 50; }

int main() {
    // We "Inject" the fake function into the API struct
    HardwareAPI mock_api = { .read_sensor = fake_read };

    assert(check_alarm(&mock_api) == 0);
    return 0;
}

